// Lesson 4: While Let
// `while let` keeps looping while the pattern matches.

fn countdown(n: i64) -> Option<i64> {
    if n > 0 {
        Some(n - 1)
    } else {
        None
    }
}

fn main() {
    var opt: Option<i64> = Some(3);
    while let Some(value) = opt {
        println(value);
        opt = countdown(value);
    }
    println("done");
}

// Lesson 5: Actors Intro
// A simple counter actor that tracks a value.
// Send it a message with `await`.

actor Counter {
    var count: i64;

    receive fn increment() -> i64 {
        count = count + 1;
        println(count);
        count
    }
}

fn main() {
    let counter = spawn Counter(count: 0);
    await counter.increment();
    await counter.increment();
    await counter.increment();
}

// Lesson 6: Actor Messaging
// Spawn several actors and send each its own message.
// Each actor runs concurrently on its own task.

actor Worker {
    let id: i64;

    receive fn task(name: string) -> i64 {
        println(f"Worker {id} got task: {name}");
        id
    }
}

fn main() {
    let w1 = spawn Worker(id: 1);
    let w2 = spawn Worker(id: 2);
    await w1.task("build widgets");
    await w2.task("paint widgets");
}

