// Lesson 9: Option Type
// TODO: Handle the None case so the program prints "not found".

fn find(items: i64, target: i64) -> Option<i64> {
    if target <= items {
        Some(target)
    } else {
        None
    }
}

fn main() {
    match find(10, 5) {
        Some(x) => println(f"found: {x}"),
        None => println("not found"),
    }
    match find(3, 7) {
        Some(x) => println(f"found: {x}"),
        None => println("not found"),
    }
}

