// Lesson 12: Async / Await
// Hew has no `async fn` — actors are the unit of concurrency.
// `await` sends a message to an actor and waits for its reply.

fn fib(n: i64) -> i64 {
    if n <= 1 { n }
    else { fib(n - 1) + fib(n - 2) }
}

actor Calculator {
    receive fn compute(n: i64) -> i64 {
        fib(n)
    }
}

fn main() {
    let calc = spawn Calculator;
    match await calc.compute(10) {
        Ok(result) => println(f"fib(10) = {result}"),
        Err(_) => println("failed"),
    }
}

